import{_ as h,C as a,o as c,c as i,a3 as o,E as n,w as s,j as t,a as e}from"./chunks/framework.Bl0ia6y7.js";const g="/S32-User-Manual/versions/v0.9.0/screens/perform/macro_rows_lfo.png",b=JSON.parse('{"title":"LFO parameter macro rows","description":"","frontmatter":{},"headers":[],"relativePath":"perform/macro-rows/lfo-parameter.md","filePath":"perform/macro-rows/lfo-parameter.md"}'),m={name:"perform/macro-rows/lfo-parameter.md"};function p(u,r,f,L,F,O){const d=a("ScreenHighlight"),l=a("ManualRelated");return c(),i("div",null,[r[2]||(r[2]=o('<h1 id="lfo-parameter-macro-rows" tabindex="-1">LFO parameter macro rows <a class="header-anchor" href="#lfo-parameter-macro-rows" aria-label="Permalink to &quot;LFO parameter macro rows&quot;">​</a></h1><p><strong>LFO parameter</strong> macros let the knob <strong>adjust an LFO</strong> — its rate, depth, phase, and so on. The LFO then modulates whatever you assigned it to (macros, device parameters, etc.).</p><p>This is <strong>knob → LFO</strong>, not <strong>LFO → macro</strong>. If an LFO is modulating a CC macro, you see the <strong><code>~</code></strong> badge on a <a href="./classic-midi">classic MIDI row</a>, not an LFO-parameter row.</p><p><img src="'+g+'" alt="LFO parameter macro rows on Perform" class="screen"></p><table tabindex="0"><thead><tr><th>Row</th><th>Mode</th><th>Target</th><th>Example in screenshot</th></tr></thead><tbody><tr><td><strong>0</strong></td><td><strong>sLFO</strong></td><td><strong>L1</strong> · Rate</td><td>S32 LFO 1 rate (synced division)</td></tr><tr><td><strong>1</strong></td><td><strong>sLFO</strong></td><td><strong>L2</strong> · Depth</td><td>S32 LFO 2 depth (20–80%)</td></tr><tr><td><strong>2</strong></td><td><strong>sLFO</strong></td><td><strong>L3</strong> · Phase</td><td>S32 LFO 3 phase (0–180°)</td></tr><tr><td><strong>3</strong></td><td><strong>cLFO</strong></td><td><strong>L4</strong> · Frequency</td><td>CV16 LFO 4 frequency (Hz)</td></tr></tbody></table><h2 id="reading-an-lfo-parameter-row" tabindex="-1">Reading an LFO parameter row <a class="header-anchor" href="#reading-an-lfo-parameter-row" aria-label="Permalink to &quot;Reading an LFO parameter row&quot;">​</a></h2>',6)),n(d,{class:"screen-highlight--macro-rows",src:"/screens/perform/macro_rows_lfo.png",alt:"LFO parameter macro rows",x:0,y:20,w:66.4,h:80,label:"Rows"},{default:s(()=>[...r[0]||(r[0]=[t("p",null,[t("strong",null,"Mode"),e(" ("),t("code",null,"sLFO"),e(" or "),t("code",null,"cLFO"),e(") → "),t("strong",null,"which LFO"),e(" ("),t("code",null,"L1"),e("–"),t("code",null,"L16"),e(") → "),t("strong",null,"which parameter"),e(" (Rate, Depth, …) → "),t("strong",null,"live value"),e(" on the far right.")],-1)])]),_:1}),r[3]||(r[3]=o('<h3 id="mode" tabindex="-1">Mode <a class="header-anchor" href="#mode" aria-label="Permalink to &quot;Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tag</th><th>Meaning</th></tr></thead><tbody><tr><td><code>sLFO</code></td><td><strong>S32 LFO</strong> — one of the LFOs in the project (<a href="./../../lfos/">LFO menu</a>)</td></tr><tr><td><code>cLFO</code></td><td><strong>CV16 LFO</strong> — an LFO on a connected <a href="./../../cv16/">CV16 expander</a></td></tr></tbody></table><h3 id="which-lfo" tabindex="-1">Which LFO <a class="header-anchor" href="#which-lfo" aria-label="Permalink to &quot;Which LFO&quot;">​</a></h3><p><code>L1</code> … <code>L16</code> — the LFO index in that pool (LFO 1, LFO 2, …).</p><h3 id="which-parameter" tabindex="-1">Which parameter <a class="header-anchor" href="#which-parameter" aria-label="Permalink to &quot;Which parameter&quot;">​</a></h3><p>The LFO field the knob edits: <strong>Rate</strong>, <strong>Depth</strong>, <strong>Phase</strong>, <strong>Frequency</strong>, <strong>Amplitude</strong>, and others. Available fields depend on the mode — see the <a href="./../../macros/s32-lfo-parameter">S32 LFO macro</a> and <a href="./../../macros/cv16-lfo">CV16 LFO macro</a> grids.</p><h3 id="live-value" tabindex="-1">Live value <a class="header-anchor" href="#live-value" aria-label="Permalink to &quot;Live value&quot;">​</a></h3><p>Formatted for that parameter: musical rates (<strong>1/8</strong>, <strong>1/32</strong>), <strong>%</strong>, <strong>°</strong>, <strong>Hz</strong>, etc.</p><h2 id="s32-vs-cv16-lfo" tabindex="-1">S32 vs CV16 LFO <a class="header-anchor" href="#s32-vs-cv16-lfo" aria-label="Permalink to &quot;S32 vs CV16 LFO&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><strong>sLFO</strong></th><th><strong>cLFO</strong></th></tr></thead><tbody><tr><td><strong>LFOs live in</strong></td><td>S32 project</td><td>CV16 expander module</td></tr><tr><td><strong>Needs hardware</strong></td><td>No</td><td>CV16 connected</td></tr><tr><td><strong>Typical use</strong></td><td>Modulate rack devices and MIDI macros</td><td>Eurorack / CV-centric setups</td></tr></tbody></table><p><strong>CV16 direct voltage</strong> on a jack (not an LFO field) is covered in <a href="./cv16-control">CV16 control</a>.</p>',11)),n(l,null,{default:s(()=>[...r[1]||(r[1]=[t("ul",null,[t("li",null,[t("a",{href:"./"},"Macro rows overview")]),t("li",null,[t("a",{href:"./../../concepts/modulation"},"Modulation"),e(" — What the LFO does after you set its rate/depth")]),t("li",null,[t("a",{href:"./../../lfos/"},"LFOs"),e(" — LFO editor and assignments")])],-1)])]),_:1})])}const v=h(m,[["render",p]]);export{b as __pageData,v as default};
